// Aggregate last 7 days of compat events into a weekly summary
const rows = $input.all().map(r => r.json);
const cutoff = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
const week = rows.filter(r => r.timestamp && r.timestamp >= cutoff);

if (week.length === 0) {
  return [{ json: { summary: 'No compatibility searches this week.' } }];
}

// Counts
const totalSearches = week.filter(r => r.event === 'model_selected').length;
const noResults = week.filter(r => r.event === 'no_results').length;
const clicks = week.filter(r => r.event === 'product_clicked').length;

// Top brands
const brandCounts = {};
week.filter(r => r.event === 'model_selected').forEach(r => {
  brandCounts[r.brand] = (brandCounts[r.brand] || 0) + 1;
});
const topBrands = Object.entries(brandCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([b, n]) => `${b} (${n})`)
  .join(', ');

// Top models
const modelCounts = {};
week.filter(r => r.event === 'model_selected').forEach(r => {
  const key = `${r.brand} ${r.model}`;
  modelCounts[key] = (modelCounts[key] || 0) + 1;
});
const topModels = Object.entries(modelCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([m, n]) => `${m} (${n})`)
  .join('\n  • ');

// No-result models
const noResultModels = [...new Set(
  week.filter(r => r.event === 'no_results').map(r => `${r.brand} ${r.model} (${r.tonnage}T)`)
)].join(', ') || 'None';

// Top clicked products
const productCounts = {};
week.filter(r => r.event === 'product_clicked').forEach(r => {
  productCounts[r.productName] = (productCounts[r.productName] || 0) + 1;
});
const topProducts = Object.entries(productCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([p, n]) => `${p} (${n})`)
  .join(', ') || 'None';

const summary = `📊 BIH Compatibility Finder — Weekly Report
` +
  `Week ending: ${new Date().toLocaleDateString('en-CA')}\n\n` +
  `🔍 Total model searches: ${totalSearches}\n` +
  `✅ Product clicks: ${clicks}\n` +
  `⚠️  No-result searches: ${noResults}\n\n` +
  `🏆 Top brands searched:\n  ${topBrands}\n\n` +
  `🔧 Top models searched:\n  • ${topModels}\n\n` +
  `❌ Models with no product match (add to catalog?):\n  ${noResultModels}\n\n` +
  `🛒 Most-clicked products:\n  ${topProducts}`;

return [{ json: { summary } }];
